/**
 * AI 模型服务
 * 不同任务自动选择最合适的模型
 */

export type AIModel = 'doubao-pro' | 'doubao-lite' | 'doubao-mini' | 'deepseek-reasoner'
export type TaskType = 'creative' | 'summary' | 'classification' | 'logic' | 'extraction'

// 模型能力映射
const ModelTaskMapping: Record<TaskType, AIModel> = {
  creative: 'doubao-pro',         // 章节生成、创意续写
  summary: 'doubao-lite',         // 摘要、结构化分析
  classification: 'doubao-mini',  // 极速分类
  logic: 'deepseek-reasoner',     // 逻辑校验、一致性检查
  extraction: 'doubao-lite',      // 事实提取
}

// 模型配置
interface ModelConfig {
  maxTokens: number
  temperature: number
  topP: number
  presencePenalty: number
  frequencyPenalty: number
}

const ModelConfigs: Record<AIModel, ModelConfig> = {
  'doubao-pro': {
    maxTokens: 4096,
    temperature: 0.8,
    topP: 0.9,
    presencePenalty: 0.1,
    frequencyPenalty: 0.1,
  },
  'doubao-lite': {
    maxTokens: 2048,
    temperature: 0.3,
    topP: 0.85,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
  'doubao-mini': {
    maxTokens: 1024,
    temperature: 0.1,
    topP: 0.7,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
  'deepseek-reasoner': {
    maxTokens: 8192,
    temperature: 0.2,
    topP: 0.95,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
}

class AIModelService {
  /**
   * 根据任务类型选择最优模型
   */
  selectModel(taskType: TaskType): AIModel {
    return ModelTaskMapping[taskType] || 'doubao-pro'
  }

  /**
   * 获取模型配置
   */
  getModelConfig(model: AIModel): ModelConfig {
    return ModelConfigs[model] || ModelConfigs['doubao-pro']
  }

  /**
   * 调用 AI 模型 (非流式)
   */
  async call(
    taskType: TaskType,
    prompt: string,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<{ success: boolean; content?: string; error?: string }> {
    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      const result = await window.electronAPI.ai.call(prompt, {
        model,
        ...config,
        systemPrompt: options?.systemPrompt,
      })

      return result
    } catch (error: unknown) {
      const msg = error instanceof Error ? error.message : String(error)
      return { success: false, error: msg }
    }
  }

  /**
   * 流式调用 AI 模型
   */
  async stream(
    taskType: TaskType,
    prompt: string,
    onChunk: (chunk: string, done: boolean) => void,
    onError?: (error: string) => void,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<void> {
    return new Promise((resolve) => {
      let settled = false
      const finish = () => { if (!settled) { settled = true; resolve() } }

      let removeChunkListener = () => {}
      let removeErrorListener = () => {}

      try {
        const model = this.selectModel(taskType)
        const config = { ...this.getModelConfig(model), ...options }

        // 监听流式输出
        removeChunkListener = window.electronAPI.ai.onStreamChunk((chunk) => {
          if (chunk.done) {
            onChunk('', true)
            removeChunkListener()
            removeErrorListener()
            finish()
          } else {
            onChunk(chunk.content, false)
          }
        })

        // 监听错误
        removeErrorListener = window.electronAPI.ai.onStreamError((error) => {
          if (onError) onError(error)
          removeChunkListener()
          removeErrorListener()
          finish()
        })

        // 发起流式请求
        window.electronAPI.ai.stream(prompt, {
          model,
          ...config,
          systemPrompt: options?.systemPrompt,
        }).catch((e: unknown) => {
          const msg = e instanceof Error ? e.message : String(e)
          if (onError) onError(msg)
          finish()
        })
      } catch (error: unknown) {
        const msg = error instanceof Error ? error.message : String(error)
        if (onError) onError(msg)
        finish()
      }
    })
  }

  /**
   * 测试模型连接
   */
  async testConnection(model: AIModel): Promise<boolean> {
    try {
      const result = await window.electronAPI.ai.testConnection(model)
      if (!result || typeof result !== 'object') return false
      return !!(result.success && result.result)
    } catch {
      return false
    }
  }
}

// 单例导出
const aiModelService = new AIModelService()
export default aiModelService

/**
 * 事实提取服务
 * 自动从章节内容中提取战力、物品、关系、伏笔等事实
 */

import aiModelService from './aiModels'
import factsStore, { Fact } from '../db'

// 提取结果类型
export interface ExtractedFact extends Omit<Fact, 'id' | 'createdAt'> {
  confidence: number // 置信度 0-1
}

class FactExtractor {
  /**
   * 从章节内容提取事实
   */
  async extract(
    chapterContent: string,
    chapterNumber: number
  ): Promise<ExtractedFact[]> {
    try {
      const systemPrompt = `
你是小说事实提取专家。请从以下章节内容中提取关键事实信息，返回严格的JSON格式数组。

提取规则：
1. 战力信息(type="power")：角色的等级、实力、功法等
2. 物品信息(type="item")：武器、丹药、宝物等
3. 关系信息(type="relation")：角色之间的关系（朋友、敌人、师徒、夫妻等）
4. 伏笔信息(type="foreshadow")：后续可能用到的线索、未解开的谜团

每个事实必须包含：
- type: 类型（power/item/relation/foreshadow）
- subject: 主体（如"林枫"）
- object: 客体（可选，如"青云子"）
- content: 事实描述（如"林枫修炼到炼气三层"）
- chapterStart: 章节号（传入的 ${chapterNumber}）
- chapterEnd: 章节号（传入的 ${chapterNumber}）
- confidence: 置信度 0-1

返回格式示例：
[
  {
    "type": "power",
    "subject": "林枫",
    "object": "",
    "content": "林枫突破到炼气三层，实力提升三倍",
    "chapterStart": ${chapterNumber},
    "chapterEnd": ${chapterNumber},
    "confidence": 0.95
  }
]

只返回JSON，不要其他内容。
`

      const result = await aiModelService.call(
        'extraction',
        chapterContent,
        { systemPrompt }
      )

      if (!result.success || !result.content) {
        return []
      }

      // 解析提取结果
      let extractedFacts: ExtractedFact[]
      try {
        extractedFacts = JSON.parse(result.content.trim())
      } catch (parseError) {
        console.error('解析提取结果失败:', parseError)
        return []
      }

      // 结构验证：过滤掉字段不完整的事实
      const validTypes = ['power', 'item', 'relation', 'foreshadow']
      return extractedFacts.filter(f =>
        f && validTypes.includes(f.type)
        && f.subject && typeof f.content === 'string'
      )
    } catch (error) {
      console.error('事实提取失败:', error)
      return []
    }
  }

  /**
   * 批量保存事实到数据库
   */
  async saveFacts(facts: ExtractedFact[]): Promise<string[]> {
    const result = await factsStore.appendFacts(facts.map(f => ({
      type: f.type,
      subject: f.subject,
      object: f.object,
      content: f.content,
      chapterStart: f.chapterStart,
      chapterEnd: f.chapterEnd,
      confidence: f.confidence ?? 1.0,
    })))
    return result.success ? ['ok'] : []
  }

  /**
   * 自动提取并保存（用户确认后调用）
   */
  async extractAndSave(
    chapterContent: string,
    chapterNumber: number
  ): Promise<string[]> {
    const facts = await this.extract(chapterContent, chapterNumber)
    // 过滤置信度低于0.7的结果
    const highConfidenceFacts = facts.filter(f => f.confidence >= 0.7)
    return this.saveFacts(highConfidenceFacts)
  }

  /**
   * 验证事实一致性
   */
  async verifyConsistency(
    newFacts: ExtractedFact[],
    existingFacts: Fact[]
  ): Promise<Array<{ fact: ExtractedFact; conflict?: Fact; message: string }>> {
    const conflicts: Array<{ fact: ExtractedFact; conflict?: Fact; message: string }> = []

    for (const newFact of newFacts) {
      // 检查是否与现有事实冲突
      const conflicting = existingFacts.find(f => {
        if (f.subject !== newFact.subject) return false

        // 相同主体的战力信息冲突检查
        if (f.type === 'power' && newFact.type === 'power') {
          // 简单的冲突检测：如果新事实表明战力下降但没有合理解释
          const oldLevel = this.extractPowerLevel(f.content)
          const newLevel = this.extractPowerLevel(newFact.content)
          return oldLevel === null || newLevel === null ? false : newLevel < oldLevel
        }

        // 关系信息冲突检查
        if (f.type === 'relation' && newFact.type === 'relation') {
          return f.object === newFact.object && f.content !== newFact.content
        }

        return false
      })

      if (conflicting) {
        conflicts.push({
          fact: newFact,
          conflict: conflicting,
          message: `检测到事实冲突：现有记录 "${conflicting.content}" 与新提取的 "${newFact.content}" 不一致`
        })
      }
    }

    return conflicts
  }

  /**
   * 辅助方法：提取战力等级
   */
  private extractPowerLevel(content: string): number | null {
    const regex = /炼气(\d+)/
    const match = content.match(regex)
    if (match) return parseInt(match[1])

    const regex2 = /筑基(\d+)/i
    const match2 = content.match(regex2)
    if (match2 && match2[1]) return parseInt(match2[1], 10) + 10

    return null
  }
}

// 单例导出
const factExtractor = new FactExtractor()
export default factExtractor

/**
 * 多 Agent 并行任务服务
 * 用于复杂任务的并行多路 AI 分析（如逻辑校验、矛盾检测）
 */

import aiModelService, { TaskType as AIModelTaskType } from './aiModels'
import { TASKS, buildContextBlock } from '../prompts'
import type { TaskType } from '../prompts/tasks'

export interface AgentTask {
  id: string
  name: string
  /** 调用的 taskType，对应 aiModels 的任务类型映射 */
  taskType: AIModelTaskType
  prompt: string
  systemPrompt?: string
}

export interface AgentResult {
  id: string
  name: string
  success: boolean
  content?: string
  error?: string
  duration: number
}

// 逻辑校验 4 路子任务
export function buildLogicCheckTasks(
  chapterContent: string,
  context: {
    facts?: string
    characters?: string
    worldRules?: string
  }
): AgentTask[] {
  const contextBlock = buildContextBlock({
    chapterContent,
    facts: context.facts,
    characters: context.characters,
    worldRules: context.worldRules,
  })

  const buildTask = (taskKey: TaskType): AgentTask => {
    const task = TASKS[taskKey]
    return {
      id: taskKey.replace('Check', '-check'),
      name: task.name,
      taskType: task.taskType,
      prompt: task.role_persona + '\n\n' + contextBlock + '\n' + task.task,
    }
  }

  return [
    buildTask('powerCheck' as TaskType),
    buildTask('timelineCheck' as TaskType),
    buildTask('characterCheck' as TaskType),
    buildTask('causalCheck' as TaskType),
  ]
}

// 并行执行多个 agent
export async function runAgents(
  tasks: AgentTask[],
  onResult?: (result: AgentResult) => void
): Promise<AgentResult[]> {
  const results = await Promise.all(
    tasks.map(async (task) => {
      const taskStart = Date.now()
      try {
        const result = await aiModelService.call(
          task.taskType,
          task.prompt,
          task.systemPrompt ? { systemPrompt: task.systemPrompt } : {}
        )
        const agentResult: AgentResult = {
          id: task.id,
          name: task.name,
          success: result.success,
          content: result.content,
          error: result.error,
          duration: Date.now() - taskStart,
        }
        onResult?.(agentResult)
        return agentResult
      } catch (err: any) {
        const agentResult: AgentResult = {
          id: task.id,
          name: task.name,
          success: false,
          error: err?.message || '未知错误',
          duration: Date.now() - taskStart,
        }
        onResult?.(agentResult)
        return agentResult
      }
    })
  )
  return results
}

// 汇总多个 agent 结果为可读报告
export function summarizeResults(results: AgentResult[]): string {
  const lines: string[] = ['## 逻辑校验报告\n']
  const successCount = results.filter(r => r.success).length
  const totalDuration = results.reduce((sum, r) => sum + r.duration, 0)

  lines.push(`**检测范围：** ${results.length} 项  |  **耗时：** ${(totalDuration / 1000).toFixed(1)}s\n`)

  for (const r of results) {
    const icon = r.success ? '✅' : '❌'
    lines.push(`### ${icon} ${r.name}`)
    if (r.success && r.content) {
      lines.push(r.content.trim())
    } else if (!r.success) {
      lines.push(`**错误：** ${r.error}`)
    }
    lines.push('')
  }

  lines.push(`---\n*由 ${successCount}/${results.length} 个子 agent 协作完成*`)
  return lines.join('\n')
}

/**
 * 语义搜索服务
 * 使用 @xenova/transformers 本地生成 embeddings，实现语义相似度搜索
 */

import { pipeline, FeatureExtractionPipeline } from '@xenova/transformers'

export interface SearchResult {
  chapterPath: string
  chapterName: string
  score: number
  snippet: string
  matchedWords: string[]
}

export interface ChapterEntry {
  path: string
  name: string
  content: string
}

// 单例模式，延迟加载模型（~90MB，首次调用时）
let serviceInstance: SemanticSearchService | null = null

class SemanticSearchService {
  private pipeline: FeatureExtractionPipeline | null = null
  private embeddings: Map<string, number[]> = new Map() // path → embedding
  private chapters: Map<string, ChapterEntry> = new Map() // path → chapter data
  private modelReady = false
  private indexing = false // P1: 并发锁
  private pendingResolve: Array<(chapters: ChapterEntry[]) => void> = []

  // 延迟加载模型
  async ensureModel(): Promise<void> {
    if (this.pipeline) return

    try {
      this.pipeline = await pipeline('feature-extraction', 'Xenova/m-MiniLM-L6-v2')
      this.modelReady = true
      console.log('[SemanticSearch] 模型加载完成')
    } catch (err) {
      this.modelReady = false
      // 提供清晰的错误类型，方便上层降级判断
      const msg = err instanceof Error ? err.message : String(err)
      if (msg.includes('WASM') || msg.includes('WebAssembly') || msg.includes('browser')) {
        throw new Error('SEMANTIC_NOT_SUPPORTED')
      }
      throw new Error(`语义模型加载失败: ${msg}`)
    }
  }

  // 对单段文本生成 embedding（384维向量）
  async embedText(text: string): Promise<number[]> {
    await this.ensureModel()
    if (!this.pipeline) throw new Error('模型未初始化')

    // 截断超长文本（模型 max_tokens 限制）
    const truncated = text.length > 8192 ? text.slice(0, 8192) : text

    const output = await this.pipeline(truncated, {
      pooling: 'mean',
      normalize: true,
    })

    return Array.from(output.data)
  }

  // 批量索引章节（不重复读文件，直接用传入的 chapters）
  // P1: 加了并发锁，多个同时调用时只执行一次，其余等待
  async indexChapters(chapters: ChapterEntry[]): Promise<{ total: number; duration: number }> {
    // 如果正在索引，等待当前索引完成
    if (this.indexing) {
      return new Promise((resolve) => {
        this.pendingResolve.push((chs) => resolve({ total: chs.length, duration: 0 }))
      })
    }

    this.indexing = true
    const start = Date.now()
    let count = 0

    try {
      for (const ch of chapters) {
        if (!ch.content || ch.content.length < 10) continue
        try {
          const emb = await this.embedText(ch.content)
          this.embeddings.set(ch.path, emb)
          this.chapters.set(ch.path, ch)
          count++
        } catch (err) {
          console.warn(`[SemanticSearch] 索引失败: ${ch.path}`, err)
        }
      }

      // 通知所有等待中的调用
      const result = { total: count, duration: Date.now() - start }
      for (const resolve of this.pendingResolve) {
        resolve(chapters)
      }
      this.pendingResolve = []
      return result
    } finally {
      this.indexing = false
    }
  }

  // 语义搜索
  async search(query: string, topK: number = 5): Promise<SearchResult[]> {
    if (this.embeddings.size === 0) {
      return []
    }

    const queryEmb = await this.embedText(query)
    const results: Array<{ path: string; score: number }> = []

    for (const [path, emb] of this.embeddings) {
      const score = cosineSimilarity(queryEmb, emb)
      results.push({ path, score })
    }

    // 按相似度降序
    results.sort((a, b) => b.score - a.score)

    // 构建返回结果，截取片段
    return results.slice(0, topK).map((r) => {
      const ch = this.chapters.get(r.path)
      return {
        chapterPath: r.path,
        chapterName: ch?.name || '',
        score: r.score,
        snippet: ch?.content.slice(0, 200) + '...' || '',
        matchedWords: extractMatchedWords(query, ch?.content || ''),
      }
    })
  }

  // 搜索指定章节范围
  async searchRange(
    query: string,
    range: { start?: number; end?: number },
    topK: number = 5
  ): Promise<SearchResult[]> {
    // 过滤出范围内的章节
    const filteredEntries = Array.from(this.chapters.entries()).filter(([path]) => {
      const match = path.match(/第(\d+)章/)
      if (!match) return true
      const num = parseInt(match[1])
      if (range.start && num < range.start) return false
      if (range.end && num > range.end) return false
      return true
    })

    const filtered: ChapterEntry[] = filteredEntries.map(([, ch]) => ch)
    const originalEmbeddings = new Map(this.embeddings)

    // 临时索引范围
    this.embeddings.clear()
    this.chapters.clear()
    for (const ch of filtered) {
      const emb = originalEmbeddings.get(ch.path)
      if (emb) {
        this.embeddings.set(ch.path, emb)
        this.chapters.set(ch.path, ch)
      }
    }

    const results = await this.search(query, topK)

    // 恢复完整索引
    this.embeddings = originalEmbeddings
    this.chapters.clear()
    for (const [path, emb] of originalEmbeddings) {
      // 重新构建 chapters map（需要重新从外部注入）
    }

    return results
  }

  // 判断模型是否已加载
  isReady(): boolean {
    return this.modelReady
  }

  // 获取索引状态
  getStats(): { indexedChapters: number; modelReady: boolean } {
    return {
      indexedChapters: this.embeddings.size,
      modelReady: this.modelReady,
    }
  }
}

// 余弦相似度
function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length !== b.length) return 0
  let dot = 0
  let normA = 0
  let normB = 0
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i]
    normA += a[i] * a[i]
    normB += b[i] * b[i]
  }
  const denominator = Math.sqrt(normA) * Math.sqrt(normB)
  return denominator === 0 ? 0 : dot / denominator
}

// 提取匹配的关键词（用于显示）
function extractMatchedWords(query: string, content: string): string[] {
  const words = query.trim().split(/\s+/).filter((w) => w.length > 1)
  const matched: string[] = []
  const lowerContent = content.toLowerCase()
  for (const word of words) {
    if (lowerContent.includes(word.toLowerCase())) {
      matched.push(word)
    }
  }
  return matched
}

// 导出单例获取函数
export function getSemanticSearchService(): SemanticSearchService {
  if (!serviceInstance) {
    serviceInstance = new SemanticSearchService()
  }
  return serviceInstance
}

export default getSemanticSearchService

/**
 * Prompt 体系统一导出
 *
 * 使用方式：
 * import { TASKS, buildContextBlock } from '../prompts'
 */

import TOMATO_RULES_TEXT from './tomatoRules'
import { ROLES } from './roles'
import { TASKS, buildContextBlock, TaskType } from './tasks'
import { LOGIC_OUTPUT, REMOVE_AI_OUTPUT, RHYTHM_OUTPUT, SLAP_FACE_OUTPUT } from './outputs'

export { TOMATO_RULES_TEXT, ROLES, TASKS, buildContextBlock, type TaskType }
export { LOGIC_OUTPUT, REMOVE_AI_OUTPUT, RHYTHM_OUTPUT, SLAP_FACE_OUTPUT }

// 快捷函数：构建逻辑校验的 prompt
export function buildLogicCheckPrompt(
  taskType: 'power' | 'timeline' | 'character' | 'causal',
  chapterContent: string,
  context: {
    facts?: string
    characters?: string
    worldRules?: string
  }
): string {
  const taskKey = taskType + 'Check' as keyof typeof TASKS
  const task = TASKS[taskKey]
  const contextBlock = buildContextBlock({
    chapterContent,
    facts: context.facts,
    characters: context.characters,
    worldRules: context.worldRules,
  })

  return task.role_persona + '\n\n' + contextBlock + '\n' + task.task
}

// 快捷函数：构建去AI味 prompt
export function buildRemoveAIPrompt(
  selectedText: string,
  context: {
    facts?: string
    characters?: string
  }
): string {
  const task = TASKS.removeAITrace
  const contextBlock = buildContextBlock({
    chapterContent: '',
    facts: context.facts,
    characters: context.characters,
  })

  const prompt = task.task.replace('{selectedText}', selectedText)
  return task.role_persona + '\n\n' + contextBlock + '\n' + prompt
}

// 快捷函数：构建节奏检测 prompt
export function buildRhythmCheckPrompt(
  chapterContent: string,
  chapterRange: { start: number; end: number }
): string {
  const task = TASKS.rhythmCheck
  const contextBlock = buildContextBlock({
    chapterContent,
    chapterRange,
  })

  return task.role_persona + '\n\n' + contextBlock + '\n' + task.task
}

export default {
  TOMATO_RULES_TEXT,
  ROLES,
  TASKS,
  buildContextBlock,
  buildLogicCheckPrompt,
  buildRemoveAIPrompt,
  buildRhythmCheckPrompt,
}

/**
 * 输出格式定义
 */

// 逻辑校验输出格式
export const LOGIC_OUTPUT = {
  format: 'structured' as const,
  displayTemplate: '## {{icon}} {{name}}

{{#if contradictions.length}}
