import TOMATO_RULES_TEXT from './tomatoRules'

// 上下文构建模板
export function buildContextBlock(params: {
  chapterContent: string
  facts?: string
  characters?: string
  worldRules?: string
  chapterRange?: { start: number; end: number }
}): string {
  const { chapterContent, facts, characters, worldRules, chapterRange } = params

  let ctx = ''

  if (chapterRange) {
    ctx += '【检测范围】第' + chapterRange.start + '章 ~ 第' + chapterRange.end + '章\n\n'
  }

  ctx += '【待检测章节】\n' + chapterContent + '\n\n'

  if (facts) {
    ctx += '【已知事实台账】（⚠️请自行验证原文，以下可能存在错误）\n⚠️ ' + facts + '\n\n'
  }

  if (characters) {
    ctx += '【角色设定】（⚠️请自行验证原文）\n⚠️ ' + characters + '\n\n'
  }

  if (worldRules) {
    ctx += '【世界观规则】\n' + worldRules + '\n\n'
  }

  return ctx
}

// 番茄规则文本（提取特定章节供任务使用）
function extractRules(startMarker: string, endMarker: string): string {
  const start = TOMATO_RULES_TEXT.indexOf(startMarker)
  const end = endMarker ? TOMATO_RULES_TEXT.indexOf(endMarker) : TOMATO_RULES_TEXT.length
  if (start === -1) return ''
  return TOMATO_RULES_TEXT.slice(start, end).trim()
}

